def weight(char):
    if char == '.':
        return 0
    if char.isupper():
        if char == 'Q':
            return 9
        if char == 'R':
            return 5
        if char == 'B':
            return 3
        if char == 'N':
            return 3
        if char == 'P':
            return 1
        if char == 'K':
            return 0
    else:
        if char == 'q':
            return 9
        if char == 'r':
            return 5
        if char == 'b':
            return 3
        if char == 'n':
            return 3
        if char == 'p':
            return 1
        if char == 'k':
            return 0


white_weight = 0
black_weight = 0

for i in range(8):
    line = input()
    for char in line:
        if char.isupper():
            white_weight += weight(char)
        else:
            black_weight += weight(char)

if white_weight > black_weight:
    print("White")
elif white_weight < black_weight:
    print("Black")
else:
    print("Draw")
